#include <stdio.h>
#include <stdlib.h>

#define MAXN 200005
#define MAXM 200005

typedef struct Edge {int to; struct Edge* next;} Edge;

Edge* adj[MAXN];
int visited[MAXN];
Edge edgePool[MAXM];
int edgeCnt;

void addEdge(int u, int v) {
    Edge* e = &edgePool[edgeCnt++];
    e->to = v;
    e->next = adj[u];
    adj[u] = e;
}

void dfs(int v) {
    if (visited[v]) return;
    visited[v] = 1;
    for (Edge* e = adj[v]; e; e = e->next) dfs(e->to);
}

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int n, m; scanf("%d %d", &n, &m);
        // reset structures for vertices 1..n
        for (int i = 1; i <= n; ++i) { adj[i] = NULL; visited[i] = 0; }
        edgeCnt = 0;
        for (int i = 0; i < m; ++i) {
            int a, b; scanf("%d %d", &a, &b);
            addEdge(a, b);
        }
        dfs(1);
        for (int i = 1; i <= n; ++i) {
            if (visited[i]) printf("%d ", i);
        }
        printf("\n");
    }
    return 0;
}

