    const a = data[idx++];
    const b = data[idx++];
    adj[a].push(b);
  }
  const visited = new Array(n + 1).fill(false);
  const stack = [1];
  while (stack.length) {
    const v = stack.pop();
    if (visited[v]) continue;
    visited[v] = true;
    for (const u of adj[v]) if (!visited[u]) stack.push(u);
  }
  const line = [];
  for (let i = 1; i <= n; ++i) if (visited[i]) line.push(i);
